#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e4+5;
bool w[MAXN],t[MAXN],u[MAXN];
int n,m,s,d,f[MAXN];
vector<int> e[MAXN],E[MAXN],ee[MAXN];
map<PII,bool> mp;
void dfs(int x)
{
    if(w[x])return;
    w[x]=true;
    t[x]=true;
    for(int i=0,to;i<E[x].size();i++)
    {
        to=E[x][i];
        dfs(to);
    }
}
signed main(void)
{
    n=read();
    m=read();
    FOR(i,1,m)
    {
        int x=read(),y=read();
        if(mp[mk(x,y)]||x==y)continue;
        mp[mk(x,y)]=true;
        e[x].pb(y);
        E[y].pb(x);
    }
    s=read();
    d=read();
    dfs(d);
    FOR(i,1,n)
    {
        u[i]=true;
        for(int j=0;j<e[i].size();++j)
        {
            if(!t[e[i][j]])u[i]=false;
        }
    }
    FOR(i,1,n)
    {
        for(int j=0;j<e[i].size();++j)
        {
            if(u[e[i][j]])ee[i].pb(e[i][j]);
        }
    }
    cl(w);
    queue<pair<int,int>> q;
    q.push(mk(s,0));
    wh(!q.empty())
    {
        pair<int,int> p=q.front();
        q.pop();
        int l=p.fst,r=p.snd;
        if(w[l])continue;
        w[l]=true;
        f[l]=r;
        for(int i=0;i<ee[l].size();++i)
        {
            q.push(mk(ee[l][i],r+1));
        }
    }
    if(!u[s]) NoAns
    else if(w[d])writeln(f[d]);
    else NoAns
    return false;
}
